using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// Options with the default reflection-based resolver
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

// 1️⃣ GetTypeInfo<T>() — strongly-typed metadata access
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> => Type: {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Alice", 42), personInfo);
Console.WriteLine($"Serialized: {json}");

// 2️⃣ TryGetTypeInfo<T>() — probe without throwing
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? info))
{
    Console.WriteLine($"TryGetTypeInfo<Person> succeeded: {info!.Type.Name}");
}

// Now demonstrate the "not available" path using a source-gen context
// that only knows about Person — Widget is unknown to it.
var restrictedOptions = new JsonSerializerOptions
{
    TypeInfoResolver = PersonOnlyContext.Default
};

if (restrictedOptions.TryGetTypeInfo<Widget>(out JsonTypeInfo<Widget>? widgetInfo))
{
    Console.WriteLine($"Widget info: {widgetInfo!.Type.Name}");
}
else
{
    Console.WriteLine("TryGetTypeInfo<Widget> returned false — metadata not available (no exception!)");
}

// Types
public record Person(string Name, int Age);
public record Widget(string Id, decimal Price);

// Source-generated context that only resolves Person
[JsonSerializable(typeof(Person))]
public partial class PersonOnlyContext : JsonSerializerContext;
EOF

